package com.copeinca.apicopeincaprov.integration.mail.smtp.models.custom;import com.copeinca.apicopeincaprov.global.dtos.AttachmentData;import lombok.*;import java.io.Serializable;import java.util.List;import java.util.Optional;@Getter@Setter@Builder@NoArgsConstructor@AllArgsConstructorpublic class SendEmailInput implements Serializable {    private String to;    private String cc;    private String bcc;    private String from;    private String subject;    private String mailBody;    private List<AttachmentData> attachments;    public void transformations(  ){        to      = Optional.ofNullable( to ).orElse( "" );        cc      = Optional.ofNullable( cc ).orElse( "" );        bcc     = Optional.ofNullable( bcc ).orElse( "" );    }}